const staticData = getWorkflowStaticData('global');
const baseUrl = 'https://www.gao.gov';

function collectEntries(payload) {
  if (!payload) {
    return [];
  }
  if (Array.isArray(payload)) {
    return payload;
  }
  const candidateKeys = ['results', 'data', 'nodes', 'items', 'search_results'];
  for (const key of candidateKeys) {
    const value = payload[key];
    if (Array.isArray(value)) {
      return value;
    }
    if (value && Array.isArray(value?.data)) {
      return value.data;
    }
  }
  return [];
}

function unwrap(value) {
  if (value === undefined || value === null) {
    return undefined;
  }
  if (Array.isArray(value)) {
    return unwrap(value[0]);
  }
  if (typeof value === 'object') {
    if (value.value !== undefined) {
      return unwrap(value.value);
    }
    if (value.rendered !== undefined) {
      return unwrap(value.rendered);
    }
    if (value.text !== undefined) {
      return unwrap(value.text);
    }
    if (value.url !== undefined) {
      return unwrap(value.url);
    }
    if (value.uri !== undefined) {
      return unwrap(value.uri);
    }
    if (value.href !== undefined) {
      return unwrap(value.href);
    }
    if (value.path !== undefined) {
      return unwrap(value.path);
    }
  }
  return value;
}

function extractField(entry, keys) {
  for (const key of keys) {
    const segments = key.split('.');
    let current = entry;
    for (const segment of segments) {
      if (current === undefined || current === null) {
        current = undefined;
        break;
      }
      current = current[segment];
    }
    const value = unwrap(current);
    if (value !== undefined && value !== null && value !== '') {
      return value;
    }
  }
  return undefined;
}

function sanitizeText(value) {
  const raw = unwrap(value);
  if (typeof raw !== 'string') {
    return undefined;
  }
  return raw.replace(/\s+/g, ' ').trim();
}

const payload = items[0]?.json ?? {};
const entries = collectEntries(payload);

if (!staticData.bootstrapComplete) {
  staticData.bootstrapComplete = true;
  staticData.knownDecisionIds = entries
    .map((entry) => sanitizeText(extractField(entry, ['decision_number', 'docket_number', 'appeal_number', 'nid', 'uuid', 'id', 'path', 'view_node', 'url', 'title'])))
    .filter((value) => value);
  return [];
}

const knownIds = new Set(staticData.knownDecisionIds || []);
const newItems = [];

for (const entry of entries) {
  const idCandidate = sanitizeText(extractField(entry, ['decision_number', 'docket_number', 'appeal_number', 'nid', 'uuid', 'id', 'product_number', 'title']));
  if (!idCandidate) {
    continue;
  }
  if (knownIds.has(idCandidate)) {
    continue;
  }
  const title = sanitizeText(extractField(entry, ['title', 'name', 'field_title']));
  let detailPath = sanitizeText(extractField(entry, ['path', 'link', 'url', 'view_node', 'href']));
  if (!detailPath) {
    continue;
  }
  if (!detailPath.startsWith('http')) {
    if (!detailPath.startsWith('/')) {
      detailPath = `/${detailPath}`;
    }
    detailPath = `${baseUrl}${detailPath}`;
  }
  const publishedRaw = sanitizeText(extractField(entry, ['decision_date', 'field_date', 'date', 'published_on', 'post_date']));
  const teaser = sanitizeText(extractField(entry, ['teaser', 'summary', 'excerpt', 'body']));

  knownIds.add(idCandidate);
  newItems.push({
    json: {
      id: idCandidate,
      title: title || idCandidate,
      detailUrl: detailPath,
      published: publishedRaw || null,
      teaser: teaser || null,
      rawEntry: entry
    }
  });
}

staticData.knownDecisionIds = Array.from(knownIds);
return newItems;

function stripHtml(value) {
  if (typeof value !== 'string') {
    return '';
  }
  return value.replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/\s+/g, ' ').trim();
}

function collectStrings(input, acc = []) {
  if (input === undefined || input === null) {
    return acc;
  }
  if (typeof input === 'string') {
    acc.push(input);
    return acc;
  }
  if (Array.isArray(input)) {
    for (const value of input) {
      collectStrings(value, acc);
    }
    return acc;
  }
  if (typeof input === 'object') {
    for (const value of Object.values(input)) {
      collectStrings(value, acc);
    }
  }
  return acc;
}

function resolveUrl(raw) {
  if (!raw || typeof raw !== 'string') {
    return null;
  }
  let url = raw.trim();
  if (!url) {
    return null;
  }
  if (url.startsWith('public://')) {
    const path = url.replace('public://', '').replace(/^/+/, '');
    return `https://www.gao.gov/assets/${path}`;
  }
  if (url.startsWith('//')) {
    return `https:${url}`;
  }
  if (url.startsWith('http://') || url.startsWith('https://')) {
    return url;
  }
  if (!url.startsWith('/')) {
    url = `/${url}`;
  }
  return `https://www.gao.gov${url}`;
}

